arguments.file_text:
@using sv_b9e02977fe5042e7abec798f40a24d5b.Models

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="step-list">
        @for (int i = 0; i < Steps.Length; i++)
        {
            var stepIndex = i + 1;
            var status = GetStepStatus(stepIndex);
            <li class="step-item @status" @onclick="() => HandleStepClick(stepIndex)" role="button">
                <span class="step-circle">
                    @if (status == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @stepIndex
                    }
                </span>
                <span class="step-label">@Steps[i]</span>
            </li>
            @if (i < Steps.Length - 1)
            {
                <li class="step-connector @(stepIndex < CurrentStep ? "completed" : "")" aria-hidden="true"></li>
            }
        }
    </ol>
</nav>

@code {
    private static readonly string[] Steps = ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "future";
    }

    private async Task HandleStepClick(int step)
