toolArgs.file_text:
.step-indicator {
    padding: 1rem 0;
}

.step-list {
    display: flex;
    align-items: center;
    list-style: none;
    padding: 0;
    margin: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    cursor: default;
    flex-shrink: 0;
}

.step-item.completed {
    cursor: pointer;
}

.step-circle {
    width: 2.2rem;
    height: 2.2rem;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    background: #0d6efd;
    border-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    background: #198754;
    border-color: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.8rem;
    color: #adb5bd;
    text-align: center;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    margin: 0 0.5rem;
    margin-bottom: 1.8rem;
    min-width: 1.5rem;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

