@using sv_b9e02977fe5042e7abec798f40a24d5b.Models

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="Model.Text" @bind:event="oninput"
              maxlength="@CoverLetterModel.MaxLength"
              placeholder="Write your cover letter here..."></textarea>
    <div class="form-text text-end">
        @Model.Text.Length / @CoverLetterModel.MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public CoverLetterModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
}

@using sv_b9e02977fe5042e7abec798f40a24d5b.Models

<h4 class="mb-3">Review Your Application</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@PersonalInfo.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@PersonalInfo.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@PersonalInfo.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@PersonalInfo.Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-no-border">
                <h6>@entry.Title at @entry.Company</h6>
                <p class="text-muted mb-1">
                    @entry.StartDate?.ToString("MMM yyyy") &mdash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </p>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var reference in References)
        {
            <div class="mb-2">
                <strong>@reference.Name</strong> — @reference.Relationship<br />
                <small class="text-muted">@reference.Email &middot; @reference.Phone</small>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(4)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter.Text</p>
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
            <span>Submitting...</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel PersonalInfo { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = [];
    [Parameter, EditorRequired] public CoverLetterModel CoverLetter { get; set; } = default!;
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
}

