@page "/apply"
@rendermode InteractiveServer
@using sv_b9e02977fe5042e7abec798f40a24d5b.Components.JobApplication
@using sv_b9e02977fe5042e7abec798f40a24d5b.Models
@using sv_b9e02977fe5042e7abec798f40a24d5b.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h1 class="mb-4">Job Application</h1>

    @if (submittedId is not null)
    {
        <div class="alert alert-success text-center py-5">
            <h3 class="mb-3">&#10003; Application Submitted!</h3>
            <p class="lead">Your application has been received.</p>
            <p>Application ID: <strong>@submittedId</strong></p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep"
                       CompletedSteps="completedSteps"
                       OnStepClicked="GoToStep" />

        <div class="mt-4">
            @switch (currentStep)
            {
                case 1:
                    <PersonalInfoStep Model="personalInfo" OnNext="HandleStepCompleted" />
                    break;
                case 2:
                    <WorkHistoryStep Entries="workEntries" OnBack="GoBack" OnNext="HandleStepCompleted" />
                    break;
                case 3:
                    <ReferencesStep References="references" OnBack="GoBack" OnNext="HandleStepCompleted" />
                    break;
                case 4:
                    <CoverLetterStep Model="coverLetter" OnBack="GoBack" OnNext="HandleStepCompleted" />
                    break;
                case 5:
                    <ReviewStep PersonalInfo="personalInfo"
                                WorkEntries="workEntries"
                                References="references"
                                CoverLetter="coverLetter"
                                IsSubmitting="isSubmitting"
                                OnBack="GoBack"
                                OnSubmit="HandleSubmit"
                                OnEditStep="GoToStep" />
                    break;
            }
        </div>
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = [];
    private bool isSubmitting;
    private int? submittedId;

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private CoverLetterModel coverLetter = new();

    private void HandleStepCompleted()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void GoBack()
    {
        if (currentStep > 1)
        {
            currentStep--;
        }
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
                new WorkHistory(workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate!.Value, e.IsCurrent ? null : e.EndDate, e.Description
                )).ToList()),
                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter.Text
            );

            var id = await ApplicationService.SubmitApplicationAsync(application);
            submittedId = id;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

